+// reloadController keeps the last successful transactional reload outcome and
+// the configuration to which partially applied reloads must be rolled back.
+type reloadController struct {
+	mu            sync.RWMutex
+	statePath     string
+	lastKnownGood *config.Config
+	status        api_v1.ReloadStatus
+	logger        *slog.Logger
+}
+
+func newReloadController(statePath string, enabled bool, logger *slog.Logger) *reloadController {
+	r := &reloadController{statePath: statePath, logger: logger, status: emptyReloadStatus()}
+	if !enabled {
+		return r
+	}
+	b, err := os.ReadFile(statePath)
+	if err != nil {
+		return r
+	}
+	var status api_v1.ReloadStatus
+	if err := json.Unmarshal(b, &status); err != nil || !validReloadStatus(status) {
+		logger.Warn("Ignoring invalid transactional reload status", "filename", statePath, "err", err)
+		return r
+	}
+	r.status = normalizeReloadStatus(status)
+	return r
+}
+
+func emptyReloadStatus() api_v1.ReloadStatus {
+	return api_v1.ReloadStatus{ErrorCategory: "none", AppliedReloaders: []string{}, ReloaderTimingsMS: map[string]int64{}}
+}
+
+func validReloadStatus(s api_v1.ReloadStatus) bool {
+	return s.ErrorCategory == "none" || s.ErrorCategory == "load_error" || s.ErrorCategory == "apply_error" || s.ErrorCategory == "rollback_error"
+}
+
+func normalizeReloadStatus(s api_v1.ReloadStatus) api_v1.ReloadStatus {
+	if s.AppliedReloaders == nil {
+		s.AppliedReloaders = []string{}
+	}
+	if s.ReloaderTimingsMS == nil {
+		s.ReloaderTimingsMS = map[string]int64{}
+	}
+	return s
+}
+
+func (r *reloadController) ReloadStatus() api_v1.ReloadStatus {
+	r.mu.RLock()
+	defer r.mu.RUnlock()
+	s := normalizeReloadStatus(r.status)
+	s.AppliedReloaders = slices.Clone(s.AppliedReloaders)
+	s.ReloaderTimingsMS = maps.Clone(s.ReloaderTimingsMS)
+	return s
+}
+
+func (r *reloadController) setLastKnownGood(conf *config.Config) {
+	r.mu.Lock()
+	defer r.mu.Unlock()
+	r.lastKnownGood = conf
+}
+
+func (r *reloadController) record(status api_v1.ReloadStatus) {
+	r.mu.Lock()
+	r.status = normalizeReloadStatus(status)
+	b, err := json.Marshal(r.status)
+	if err == nil {
+		tmp := r.statePath + ".tmp"
+		err = os.WriteFile(tmp, b, 0o644)
+		if err == nil {
+			err = os.Rename(tmp, r.statePath)
+		}
+	}
+	r.mu.Unlock()
+	if err != nil {
+		r.logger.Error("Failed to persist transactional reload status", "filename", r.statePath, "err", err)
+	}
+}
+
+func (r *reloadController) reload(filename string, enableExemplarStorage bool, logger *slog.Logger, noStepSubqueryInterval *safePromQLNoStepSubqueryInterval, callback func(bool), rls ...reloader) (err error) {
+	status := emptyReloadStatus()
+	status.LastReloadID = time.Now().UTC().Format(time.RFC3339)
+	defer func() {
+		status.LastReloadSuccessful = err == nil
+		if err == nil {
+			configSuccess.Set(1)
+			configSuccessTime.SetToCurrentTime()
+			callback(true)
+		} else {
+			configSuccess.Set(0)
+			callback(false)
+		}
+		r.record(status)
+	}()
+
+	conf, err := config.LoadFile(filename, agentMode, logger)
+	if err != nil {
+		status.ErrorCategory = "load_error"
+		status.ErrorMessage = err.Error()
+		return fmt.Errorf("couldn't load configuration (--config.file=%q): %w", filename, err)
+	}
+	if enableExemplarStorage && conf.StorageConfig.ExemplarsConfig == nil {
+		conf.StorageConfig.ExemplarsConfig = &config.DefaultExemplarsConfig
+	}
+
+	r.mu.RLock()
+	lastKnownGood := r.lastKnownGood
+	r.mu.RUnlock()
+	for _, rl := range rls {
+		start := time.Now()
+		applyErr := rl.reloader(conf)
+		status.ReloaderTimingsMS[rl.name] = durationToInt64Millis(time.Since(start))
+		if applyErr == nil {
+			status.AppliedReloaders = append(status.AppliedReloaders, rl.name)
+			continue
+		}
+		status.ErrorCategory = "apply_error"
+		status.ErrorMessage = applyErr.Error()
+		status.FailedReloader = rl.name
+		if len(status.AppliedReloaders) > 0 && lastKnownGood != nil {
+			status.RollbackAttempted = true
+			status.RollbackSuccessful = true
+			for _, applied := range status.AppliedReloaders {
+				for _, rollback := range rls {
+					if rollback.name != applied {
+						continue
+					}
+					if rollbackErr := rollback.reloader(lastKnownGood); rollbackErr != nil {
+						status.RollbackSuccessful = false
+						status.ErrorCategory = "rollback_error"
+						status.ErrorMessage = rollbackErr.Error()
+					}
+					break
+				}
+			}
+		}
+		return fmt.Errorf("failed to apply configuration in reloader %q: %w", rl.name, applyErr)
+	}
+
+	updateGoGC(conf, logger)
+	noStepSubqueryInterval.Set(conf.GlobalConfig.EvaluationInterval)
+	r.setLastKnownGood(conf)
+	return nil
+}
